              <button onClick={() => setShowGlossary(false)} className="p-2 hover:bg-slate-100 rounded-full">
                <X size={24} />
              </button>
            </div>
            <div className="space-y-6">
              {GLOSSARY_TERMS.map((item, idx) => (
                <div key={idx} className="pb-4 border-b border-slate-100 last:border-0">
                  <h4 className="font-bold text-royal-800 mb-1">{item.term}</h4>
                  <p className="text-sm text-slate-600 leading-relaxed">{item.definition}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

