                    className="text-xs font-bold text-gold-600 hover:text-gold-800 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    View in Context <ArrowRight size={12} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

