                  <div className="p-3 bg-slate-50 rounded-lg group-hover:bg-royal-50 transition-colors">
                    {section.icon}
                  </div>
                  <ChevronRight className="text-slate-300 group-hover:text-gold-500 transition-colors" />
                </div>
