              <div className="text-left">
                <div className="h-px w-32 bg-slate-900 mb-2"></div>
                <div className="text-xs uppercase font-bold text-slate-400">Emma Elizabeth Ryan</div>
              </div>
              <div className="text-left">
                <div className="h-px w-32 bg-slate-900 mb-2"></div>
