  const colors = {
    completed: 'bg-emerald-500 text-white border-emerald-500',
    current: 'bg-gold-500 text-white border-gold-500 shadow-lg shadow-gold-500/30',
    future: 'bg-slate-100 text-slate-400 border-slate-200'
