            title="Foundation" 
            time="Months 1-6" 
            status="current"
            onClick={() => setActiveSection('custody')} 
          />
           <TimelinePhase 
            phase="Phase 2" 
            title="Expansion" 
            time="Months 7-24" 
            status="future" 
            onClick={() => setActiveSection('custody')} 
          />
           <TimelinePhase 
            phase="Phase 3" 
            title="Near-Equal" 
            time="Month 25+" 
            status="future" 
            onClick={() => setActiveSection('custody')} 
          />
           <TimelinePhase 
            phase="Destination" 
            title="Sunrise Clause" 
            time="March 1, 2028" 
            status="future" 
            onClick={() => setActiveSection('legacy')} 
          />
